@Service
class SamlService {
    private final SamlProperties properties;

    SamlService(SamlProperties properties) {
        this.properties = properties;
    }

    public String buildAuthnRequest() {
        return Base64.getEncoder().encodeToString((
                "<saml2p:AuthnRequest xmlns:saml2p=\"urn:oasis:names:tc:SAML:2.0:protocol\" " +
                "ID=\"_" + UUID.randomUUID() + "\" Version=\"2.0\" IssueInstant=\"" + Instant.now().toString() + "\" " +
                "Destination=\"" + properties.getIdpSsoUrl() + "\" AssertionConsumerServiceURL=\"" + properties.getAcsUrl() + "\" " +
                "ProtocolBinding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\"/>"
        ).getBytes());
    }

    public String buildMetadata() {
        return "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                "<EntityDescriptor xmlns=\"urn:oasis:names:tc:SAML:2.0:metadata\" entityID=\"" + properties.getSpEntityId() + "\">" +
                "<SPSSODescriptor protocolSupportEnumeration=\"urn:oasis:names:tc:SAML:2.0:protocol\">" +
                "<AssertionConsumerService Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\" Location=\"" + properties.getAcsUrl() + "\" index=\"1\" isDefault=\"true\"/>" +
                "</SPSSODescriptor></EntityDescriptor>";
    }

    public String validateSamlResponse(String samlResponseBase64) {
        if (samlResponseBase64 == null || samlResponseBase64.isBlank()) {
            throw new IllegalArgumentException("Missing SAMLResponse");
        }
        String xml = new String(Base64.getDecoder().decode(samlResponseBase64));
        if (!xml.contains("<saml2:Assertion") && !xml.contains("<Assertion")) {
            throw new IllegalArgumentException("Invalid SAMLResponse");
        }
        return "authenticated-user";
    }
}

@RestController
@RequestMapping("/saml")
class SamlController {
    private final SamlService samlService;

    SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping(value = "/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public ResponseEntity<String> metadata() {
        return ResponseEntity.ok(samlService.buildMetadata());
    }

    @GetMapping("/login")
    public ResponseEntity<Void> login(HttpServletResponse response) {
        String authnRequest = samlService.buildAuthnRequest();
        response.setHeader(HttpHeaders.LOCATION, authnRequest);
        return ResponseEntity.status(HttpStatus.FOUND).build();
    }

    @PostMapping(value = "/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public ResponseEntity<String> acs(@RequestParam("SAMLResponse") String samlResponse) {
        String user = samlService.validateSamlResponse(samlResponse);
        return ResponseEntity.ok("SSO success for " + user);
    }

    @GetMapping("/logout")
    public ResponseEntity<String> logout() {
        return ResponseEntity.ok("Logged out");
    }
}